  "module": "01-layout.md",
  "group": "01 — Layout Components",
  "apiCount": 5,
  "apis": [
    {
      "name": "Flex",
      "purpose": "弹性布局容器，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的容器，可设置子组件间距和对齐方式",
      "anchor": "column",
      "status": "found"
