    {
      "name": "Row",
      "purpose": "沿水平方向布局的容器，可设置子组件间距和对齐方式",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈，后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件，子组件尺寸超出父组件时内容可滚动",
      "anchor": "scroll",
      "status": "found"
